#include <iostream>
#include <chrono>

int main()
{
    long long u;
    std::cin >> u;

    std::chrono::microseconds dur(u);
    auto ms = std::chrono::duration_cast<std::chrono::milliseconds>(dur);

    std::cout << "Microseconds: " << dur.count() << '\n';
    std::cout << "Milliseconds: " << ms.count() << '\n';

    return 0;
}

