solution_code:
#include <iostream>
#include <chrono>
#include <string>

std::string formatDuration(long long microseconds)
{
    std::chrono::microseconds dur(microseconds);
    auto ms = std::chrono::duration_cast<std::chrono::milliseconds>(dur);
    return std::to_string(dur.count()) + "us = " + std::to_string(ms.count()) + "ms";
}

int main()
{
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i)
    {
        long long us;
        std::cin >> us;
        std::cout << formatDuration(us) << '\n';
    }
    return 0;
}
